50	                                             cublas_wrapper_,
51	                                             allocator_,
52	                                             is_free_buffer_after_forward_,
53	                                             sparse_);
54	
55	    dynamic_decode_layer_ = new DynamicDecodeLayer<float>(vocab_size_,
56	                                                          vocab_size_padded_,
57	                                                          0,  // end_id, deprecated
58	                                                          stream_,
59	                                                          cublas_wrapper_,
60	                                                          allocator_,
61	                                                          is_free_buffer_after_forward_,
62	                                                          cuda_device_prop_);
63	}
