71	template<typename T1, typename T2>
72	void GptFP8<T1, T2>::allocateBuffer(size_t batch_size, size_t beam_width, size_t max_seq_len, size_t max_input_len)
73	{
74	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
75	    const size_t batchxbeam = batch_size * beam_width;
76	    const size_t self_cache_size =
77	        (num_layer_ / pipeline_para_.world_size_) * batchxbeam * max_seq_len * hidden_units_ / tensor_para_.world_size_;
78	    const size_t max_input_len_padded = (max_input_len + 15) / 16 * 16;
79	    if (vocab_size_ != vocab_size_padded_) {
80	        padded_embedding_kernel_     = (T2*)(allocator_->reMalloc(
81	            padded_embedding_kernel_, sizeof(T2) * hidden_units_ * vocab_size_padded_, true));
82	        padded_embedding_kernel_ptr_ = padded_embedding_kernel_;
83	    }
84	
85	    input_attention_mask_ = (T1*)(allocator_->reMalloc(
86	        input_attention_mask_, sizeof(T1) * batchxbeam * max_input_len_padded * max_input_len_padded, false));
87	    decoder_input_buf_ =
88	        (T2*)(allocator_->reMalloc(decoder_input_buf_, sizeof(T2) * batchxbeam * hidden_units_, false));
89	    decoder_output_buf_ =
90	        (T2*)(allocator_->reMalloc(decoder_output_buf_, sizeof(T2) * batchxbeam * hidden_units_, false));
91	    normed_decoder_output_buf_ =
92	        (T2*)(allocator_->reMalloc(normed_decoder_output_buf_, sizeof(T2) * batchxbeam * hidden_units_, false));
93	    logits_buf_ = (float*)(allocator_->reMalloc(logits_buf_, sizeof(float) * batchxbeam * vocab_size_padded_, false));
94	    nccl_logits_buf_ =
95	        (float*)(allocator_->reMalloc(nccl_logits_buf_, sizeof(float) * batchxbeam * vocab_size_padded_, false));
96	    cum_log_probs_  = (float*)(allocator_->reMalloc(cum_log_probs_, sizeof(float) * batchxbeam, false));
97	    finished_buf_   = (bool*)(allocator_->reMalloc(finished_buf_, sizeof(bool) * batchxbeam, false));
98	    h_finished_buf_ = new bool[batchxbeam];
99	
100	#ifdef FP8_MHA
101	    key_cache_ = (T1*)(allocator_->reMalloc(key_cache_, sizeof(T1) * self_cache_size * 2, true));
102	#else
103	    key_cache_ = (T2*)(allocator_->reMalloc(key_cache_, sizeof(T2) * self_cache_size * 2, true));
104	#endif
105	    value_cache_ = key_cache_ + self_cache_size;
106	    if (beam_width > 1) {
107	        cache_indirections_[0] =
108	            (int*)(allocator_->reMalloc(cache_indirections_[0], sizeof(int) * batchxbeam * max_seq_len * 2, true));
109	        cache_indirections_[1] = cache_indirections_[0] + batchxbeam * max_seq_len;
110	    }
111	
112	    tiled_input_ids_buf_ =
113	        (int*)(allocator_->reMalloc(tiled_input_ids_buf_, sizeof(int) * batchxbeam * max_input_len, true));
114	    tiled_input_lengths_buf_ = (int*)(allocator_->reMalloc(tiled_input_lengths_buf_, sizeof(int) * batchxbeam, true));
115	
116	    start_ids_buf_ = (int*)(allocator_->reMalloc(start_ids_buf_, sizeof(int) * batch_size, false));
117	    end_ids_buf_   = (int*)(allocator_->reMalloc(end_ids_buf_, sizeof(int) * batch_size, false));
118	
119	    transposed_output_ids_buf_ =
120	        (int*)(allocator_->reMalloc(transposed_output_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
121	    output_ids_buf_ = (int*)(allocator_->reMalloc(output_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
122	    parent_ids_buf_ = (int*)(allocator_->reMalloc(parent_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
123	    tiled_total_padding_count_ =
124	        (int*)(allocator_->reMalloc(tiled_total_padding_count_, sizeof(int) * batchxbeam * max_seq_len, true));
125	    masked_tokens_ = (bool*)(allocator_->reMalloc(masked_tokens_, sizeof(bool) * batchxbeam * max_seq_len, true));
126	
127	    context_decoder_input_buf_  = (T2*)(allocator_->reMalloc(
128	        context_decoder_input_buf_, sizeof(T2) * batchxbeam * max_input_len * hidden_units_, false));
129	    context_decoder_output_buf_ = (T2*)(allocator_->reMalloc(
130	        context_decoder_output_buf_, sizeof(T2) * batchxbeam * max_input_len * hidden_units_, false));
131	    is_allocate_buffer_         = true;
132	}
