134	template<typename T1, typename T2>
135	void GptFP8<T1, T2>::freeBuffer()
136	{
137	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
138	    if (is_allocate_buffer_) {
139	        if (vocab_size_ != vocab_size_padded_) {
140	            padded_embedding_kernel_ptr_ = nullptr;
141	            allocator_->free((void**)(&padded_embedding_kernel_));
142	        }
143	
144	        allocator_->free((void**)(&input_attention_mask_));
145	        allocator_->free((void**)(&decoder_input_buf_));
146	        allocator_->free((void**)(&decoder_output_buf_));
147	        allocator_->free((void**)(&normed_decoder_output_buf_));
148	        allocator_->free((void**)(&logits_buf_));
149	        allocator_->free((void**)(&nccl_logits_buf_));
150	        allocator_->free((void**)(&cum_log_probs_));
151	        allocator_->free((void**)(&finished_buf_));
152	        delete[] h_finished_buf_;
153	
154	        allocator_->free((void**)(&key_cache_));
155	        if (cache_indirections_[0] != nullptr) {
156	            allocator_->free((void**)(&cache_indirections_[0]));
157	        }
158	
159	        allocator_->free((void**)(&tiled_input_ids_buf_));
160	        allocator_->free((void**)(&tiled_input_lengths_buf_));
161	
162	        allocator_->free((void**)(&start_ids_buf_));
163	        allocator_->free((void**)(&end_ids_buf_));
164	
165	        allocator_->free((void**)(&transposed_output_ids_buf_));
166	        allocator_->free((void**)(&output_ids_buf_));
167	        allocator_->free((void**)(&parent_ids_buf_));
168	        allocator_->free((void**)(&tiled_total_padding_count_));
169	        allocator_->free((void**)(&masked_tokens_));
170	
171	        allocator_->free((void**)(&context_decoder_input_buf_));
172	        allocator_->free((void**)(&context_decoder_output_buf_));
173	        is_allocate_buffer_ = false;
174	    }
175	}
