178	GptFP8<T1, T2>::GptFP8(size_t           beam_width,
179	                       size_t           head_num,
180	                       size_t           size_per_head,
181	                       size_t           inter_size,
182	                       size_t           num_layer,
183	                       size_t           vocab_size,
184	                       int              start_id,
185	                       int              end_id,
186	                       NcclParam        tensor_para,
187	                       NcclParam        pipeline_para,
188	                       cudaStream_t     stream,
189	                       cublasMMWrapper* cublas_wrapper,
190	                       IAllocator*      allocator,
191	                       bool             is_free_buffer_after_forward,
192	                       cudaDeviceProp*  cuda_device_prop,
193	                       bool             sparse):
194	    BaseLayer(stream, cublas_wrapper, allocator, is_free_buffer_after_forward, cuda_device_prop, sparse),
195	    head_num_(head_num),
196	    size_per_head_(size_per_head),
197	    inter_size_(inter_size),
198	    num_layer_(num_layer),
199	    vocab_size_(vocab_size),
200	    start_id_(start_id),
201	    end_id_(end_id),
202	    hidden_units_(head_num_ * size_per_head),
203	    tensor_para_(tensor_para),
204	    pipeline_para_(pipeline_para),
205	    local_head_num_(head_num / tensor_para.world_size_)
206	{
207	    int local_vacab_size = ceil(vocab_size_ / 1.f / tensor_para_.world_size_);
208	    if (std::is_same<__nv_bfloat16, T1>::value || std::is_same<__nv_fp8_e4m3, T1>::value) {
209	        local_vacab_size = ceil(local_vacab_size / 8.f) * 8;
210	    }
211	    vocab_size_padded_ = (size_t)local_vacab_size * tensor_para_.world_size_;
212	    initialize();
213	}
