244	template<typename T1, typename T2>
245	void GptFP8<T1, T2>::forward(std::unordered_map<std::string, Tensor>*       output_tensors,
246	                             const std::unordered_map<std::string, Tensor>* input_tensors,
247	                             const GptFP8Weight<T1, T2>*                    gpt_weights)
248	{
249	    // input_tensors:
250	    //      input_ids [batch_size, max_input_length]
251	    //      input_lengths [batch_size]
252	    //      output_seq_len [batch size]
253	    //      runtime_top_k [1] or [batch_size] on cpu, optional
254	    //      runtime_top_p [1] or [batch_size] on cpu, optional
255	    //      beam_search_diversity_rate [1] or [batch_size] on cpu, optional
256	    //      temperature [1] or [batch_size] on cpu, optional
257	    //      len_penalty [1] or [batch_size] on cpu, optional
258	    //      repetition_penalty [1] or [batch_size] on cpu, optional
259	    //      random_seed [1] or [batch_size] on cpu, optional
260	    //      prefix_soft_prompt_lengths [batch_size], optional
261	    //      prefix_soft_prompt_embedding [batch_size, max_prefix_soft_prompt_length, hidden_units], optional
262	
263	    // output_tensors:
264	    //      output_ids [batch_size, beam_width, max_output_seq_len]
265	    //      sequence_length [batch_size, beam_width]
266	    //      output_cum_log_probs [request_output_seq_len, batch_size, beam_width], must be float*.
267	    //          optional. It leads to additional computing cost. If we don't need this result, don't put it.
268	
269	    // Step is from max_input_length ~ max_output_seq_len,
270	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
271	    // complete this step.
272	    // When there is no input_ids, put the start token at step 0 of output_ids_buf_. After forward, only copy
273	    // the step 1 ~ max_output_seq_len of output_ids_buf_ to output_tensors->at(0).data
274	
275	    FT_CHECK_WITH_INFO(input_tensors->size() >= 3, "input_tensors->size() >= 3");
276	    FT_CHECK_WITH_INFO(output_tensors->size() >= 2, "output_tensors->size() >= 2");
277	    FT_CHECK(input_tensors->at("input_ids").shape.size() == 2);
278	    FT_CHECK(input_tensors->at("input_lengths").shape.size() == 1);
279	    FT_CHECK(input_tensors->count("output_seq_len"));
280	    FT_CHECK(output_tensors->at("output_ids").shape.size() == 3);
281	    FT_CHECK(output_tensors->at("sequence_length").shape.size() == 2);
282	    FT_CHECK_WITH_INFO(input_tensors->at("input_ids").shape[0] == output_tensors->at("output_ids").shape[0],
283	                       "input_tensors->at(\"input_ids\").shape[0] == output_tensors->at(\"output_ids\").shape[0]");
284	
285	    // Used when inputs do not contain random_seed
286	    const size_t batch_size                    = output_tensors->at("output_ids").shape[0];
287	    const size_t beam_width                    = output_tensors->at("output_ids").shape[1];
288	    int          max_input_length              = input_tensors->at("input_ids").shape[1];
289	    const size_t max_prefix_soft_prompt_length = input_tensors->count("prefix_soft_prompt_embedding") ?
290	                                                     input_tensors->at("prefix_soft_prompt_embedding").shape[1] :
291	                                                     0;
292	    const size_t limit_len_offset              = max_prefix_soft_prompt_length + (max_input_length == 0 ? 1 : 0);
293	    const size_t max_output_seq_len            = input_tensors->at("output_seq_len").max<uint32_t>() + limit_len_offset;
294	    const size_t max_seq_len                   = max_output_seq_len;
295	    allocateBuffer(batch_size, beam_width, max_seq_len, max_input_length + max_prefix_soft_prompt_length);
296	    sync_check_cuda_error();
297	
298	    int*           sequence_lengths         = (int*)(output_tensors->at("sequence_length").data);
299	    const DataType data_type                = getTensorType<T1>();
300	    const DataType high_precision_data_type = getTensorType<T2>();
301	
302	    const int initial_step = 0;
303	
304	#ifdef FP8_MHA
305	    const std::vector<size_t> self_k_cache_shape = {num_layer_ / pipeline_para_.world_size_,
306	                                                    batch_size * beam_width,
307	                                                    local_head_num_,
308	                                                    size_per_head_ / (16 / sizeof(T1)),
309	                                                    max_output_seq_len,
310	                                                    16 / sizeof(T1)};
311	#else
312	    const std::vector<size_t> self_k_cache_shape = {num_layer_ / pipeline_para_.world_size_,
313	                                                    batch_size * beam_width,
314	                                                    local_head_num_,
315	                                                    size_per_head_ / (16 / sizeof(T2)),
316	                                                    max_output_seq_len,
317	                                                    16 / sizeof(T2)};
318	#endif
319	    const std::vector<size_t> self_v_cache_shape = {num_layer_ / pipeline_para_.world_size_,
320	                                                    batch_size * beam_width,
321	                                                    local_head_num_,
322	                                                    max_output_seq_len,
323	                                                    size_per_head_};
324	    {
325	        TensorMap input_map(*input_tensors);
326	        dynamic_decode_layer_->setup(batch_size, beam_width, &input_map);
327	        handleOptArg(&input_map, "start_id", start_ids_buf_, start_id_, batch_size);
328	        handleOptArg(&input_map, "end_id", end_ids_buf_, end_id_, batch_size);
329	    }
330	
331	    // TODO(bhsueh) Initilaize them in one kernel
332	    // initialize the output ids and parent ids
333	    cudaMemsetAsync(output_ids_buf_, 0, sizeof(int) * batch_size * beam_width * max_seq_len, stream_);
334	    cudaMemsetAsync(parent_ids_buf_, 0, sizeof(int) * batch_size * beam_width * max_seq_len, stream_);
335	    cudaMemsetAsync(tiled_total_padding_count_, 0, sizeof(int) * batch_size * beam_width, stream_);
336	    if (beam_width > 1) {
337	        cudaMemsetAsync(cache_indirections_[0], 0, 2 * sizeof(int) * batch_size * beam_width * max_seq_len, stream_);
338	    }
339	    sync_check_cuda_error();
340	    // handle first step
341	    if (input_tensors->count("prefix_soft_prompt_embedding") || max_input_length > 1) {
342	        invokeTileGptInputs(tiled_input_ids_buf_,
343	                            tiled_input_lengths_buf_,
344	                            (int*)input_tensors->at("input_ids").data,
345	                            (const int*)(input_tensors->at("input_lengths").data),
346	                            batch_size,
347	                            beam_width,
348	                            max_input_length,
349	                            stream_);
350	        sync_check_cuda_error();
351	
352	        if (input_tensors->count("prefix_soft_prompt_embedding")) {
353	            inputIdsEmbeddingLookupPosEncodingSoftPromptParam<T2> param;
354	            param.from_tensor                   = context_decoder_input_buf_;
355	            param.output_ids                    = output_ids_buf_;
356	            param.input_lengths                 = tiled_input_lengths_buf_;
357	            param.embedding_table               = gpt_weights->pre_decoder_embedding_table;
358	            param.pos_table                     = gpt_weights->position_encoding_table;
359	            param.prefix_soft_prompt_embedding  = input_tensors->at("prefix_soft_prompt_embedding").getPtr<float>();
360	            param.prefix_soft_prompt_lengths    = input_tensors->at("prefix_soft_prompt_lengths").getPtr<int>();
361	            param.input_ids                     = tiled_input_ids_buf_;
362	            param.start_step                    = 1;
363	            param.max_input_length              = max_input_length;
364	            param.max_prefix_soft_prompt_length = max_prefix_soft_prompt_length;
365	            param.batch_size                    = batch_size;
366	            param.beam_width                    = beam_width;
367	            param.hidden_units                  = hidden_units_;
368	            param.stream                        = stream_;
369	
370	            invokeInputIdsEmbeddingLookupPosEncodingSoftPrompt(param);
371	            sync_check_cuda_error();
372	            max_input_length += max_prefix_soft_prompt_length;  // view soft_prompt as input
373	        }
374	        else {
375	            pPromptTuningParam<T2> prompt_param{nullptr, 0, 0, false, nullptr};
376	            invokeInputIdsEmbeddingLookupPosEncoding(context_decoder_input_buf_,
377	                                                     output_ids_buf_,
378	                                                     gpt_weights->pre_decoder_embedding_table,
379	                                                     gpt_weights->position_encoding_table,
380	                                                     prompt_param,
381	                                                     tiled_input_ids_buf_,
382	                                                     1,
383	                                                     max_input_length,
384	                                                     max_input_length,
385	                                                     batch_size * beam_width,
386	                                                     hidden_units_,
387	                                                     stream_);
388	            sync_check_cuda_error();
389	        }
390	
391	        const int max_input_length_padded = (max_input_length + 15) / 16 * 16;
392	        invokeBuildDecoderAttentionMask(input_attention_mask_,
393	                                        tiled_input_lengths_buf_,
394	                                        nullptr,
395	                                        batch_size * beam_width,
396	                                        max_input_length_padded,
397	                                        0,
398	                                        stream_);
399	        sync_check_cuda_error();
400	
401	        std::vector<Tensor> decoder_input_tensors{
402	            Tensor{MEMORY_GPU,
403	                   high_precision_data_type,
404	                   {batch_size * beam_width, (size_t)max_input_length, hidden_units_},
405	                   context_decoder_input_buf_},
406	            Tensor{MEMORY_GPU,
407	                   data_type,
408	                   {batch_size * beam_width, 1, (size_t)max_input_length_padded, (size_t)max_input_length_padded},
409	                   input_attention_mask_},
410	            Tensor{MEMORY_GPU, TYPE_INT32, {batch_size * beam_width}, tiled_input_lengths_buf_}};
411	
412	        std::vector<Tensor> decoder_output_tensors{
413	            Tensor{MEMORY_GPU,
414	                   high_precision_data_type,
415	                   {batch_size * beam_width, (size_t)max_input_length, hidden_units_},
416	                   context_decoder_output_buf_},
417	#ifdef FP8_MHA
418	            Tensor{MEMORY_GPU, getTensorType<T1>(), self_k_cache_shape, key_cache_},
419	            Tensor{MEMORY_GPU, getTensorType<T1>(), self_v_cache_shape, value_cache_},
420	#else
421	            Tensor{MEMORY_GPU, getTensorType<T2>(), self_k_cache_shape, key_cache_},
422	            Tensor{MEMORY_GPU, getTensorType<T2>(), self_v_cache_shape, value_cache_},
423	#endif
424	            Tensor{MEMORY_GPU, data_type, {batch_size * beam_width, hidden_units_}, decoder_output_buf_}};
425	
426	        gpt_context_decoder_->forward(
427	            &decoder_output_tensors, &decoder_input_tensors, &gpt_weights->decoder_layer_weights);
428	
429	        invokeDecodingInitialize(finished_buf_,
430	                                 sequence_lengths,
431	                                 nullptr,
432	                                 cum_log_probs_,
433	                                 start_ids_buf_,
434	                                 batch_size,
435	                                 beam_width,
436	                                 max_input_length - 1,
437	                                 stream_);
438	        sync_check_cuda_error();
439	    }
440	    else if (max_input_length == 0) {
441	        max_input_length++;
442	        invokeDecodingInitialize(finished_buf_,
443	                                 sequence_lengths,
444	                                 output_ids_buf_,
445	                                 cum_log_probs_,
446	                                 start_ids_buf_,
447	                                 batch_size,
448	                                 beam_width,
449	                                 max_input_length - 1,
450	                                 stream_);
451	        std::vector<int> h_input_lengths(batch_size * beam_width, 1);
452	        cudaMemcpyAsync(tiled_input_lengths_buf_,
453	                        h_input_lengths.data(),
454	                        sizeof(int) * batch_size * beam_width,
455	                        cudaMemcpyHostToDevice,
456	                        stream_);
457	        sync_check_cuda_error();
458	    }
459	    else if (max_input_length == 1) {
460	        invokeDecodingInitialize(finished_buf_,
461	                                 sequence_lengths,
462	                                 nullptr,
463	                                 cum_log_probs_,
464	                                 start_ids_buf_,
465	                                 batch_size,
466	                                 beam_width,
467	                                 max_input_length - 1,
468	                                 stream_);
469	        sync_check_cuda_error();
470	        invokeTileGptInputs(tiled_input_ids_buf_,
471	                            tiled_input_lengths_buf_,
472	                            (int*)input_tensors->at("input_ids").data,
473	                            (const int*)(input_tensors->at("input_lengths").data),
474	                            batch_size,
475	                            beam_width,
476	                            max_input_length,
477	                            stream_);
478	        sync_check_cuda_error();
479	
480	        cudaMemcpyAsync(output_ids_buf_,
481	                        tiled_input_ids_buf_,
482	                        sizeof(int) * batch_size * beam_width,
483	                        cudaMemcpyDeviceToDevice,
484	                        stream_);
485	    }
486	
487	    if (vocab_size_ == vocab_size_padded_) {
488	        padded_embedding_kernel_ptr_ = gpt_weights->post_decoder_embedding.kernel;
489	    }
490	    else {
491	        cudaMemcpyAsync(padded_embedding_kernel_,
492	                        gpt_weights->post_decoder_embedding.kernel,
493	                        sizeof(T2) * vocab_size_ * hidden_units_,
494	                        cudaMemcpyDeviceToDevice,
495	                        stream_);
496	        sync_check_cuda_error();
497	    }
498	
499	    const size_t memory_len = max_seq_len;
500	    invokeMaskPaddingTokens(masked_tokens_,
501	                            input_tensors->at("input_lengths").getPtr<int>(),
502	                            memory_len,
503	                            max_input_length,
504	                            initial_step,
505	                            batch_size,
506	                            beam_width,
507	                            stream_);
508	
509	    for (int step = max_input_length; step < (int)max_output_seq_len; step++) {
510	        const int src_indir_idx = (step - max_input_length) % 2;
511	        const int tgt_indir_idx = 1 - src_indir_idx;
512	
513	        const size_t local_batch_size = getLocalBatchSize(batch_size, 1, pipeline_para_.world_size_);
514	        FT_CHECK(batch_size % local_batch_size == 0);
515	        const size_t iteration_num = batch_size / local_batch_size;
516	
517	        for (uint ite = 0; ite < iteration_num; ++ite) {
518	            const int id_offset               = ite * local_batch_size * beam_width;
519	            const int hidden_units_offset     = id_offset * hidden_units_;
520	            const int vocab_size_units_offset = id_offset * vocab_size_padded_;
521	
522	            if (!(max_input_length > 1 && step == max_input_length)) {
523	                if (pipeline_para_.rank_ == 0) {
524	                    invokeEmbeddingLookupPosEncodingPadCount(decoder_input_buf_ + hidden_units_offset,
525	                                                             gpt_weights->pre_decoder_embedding_table,
526	                                                             gpt_weights->position_encoding_table,
527	                                                             output_ids_buf_ + id_offset,
528	                                                             tiled_total_padding_count_ + id_offset,
529	                                                             local_batch_size * beam_width,
530	                                                             hidden_units_,
531	                                                             (T2)(1.0f),
532	                                                             step - 1,
533	                                                             batch_size * beam_width,
534	                                                             0,
535	                                                             stream_);
536	                    sync_check_cuda_error();
537	                }
538	
539	                TensorMap decoder_input_tensors(
540	                    {{"decoder_input",
541	                      Tensor(MEMORY_GPU,
542	                             high_precision_data_type,
543	                             {local_batch_size * beam_width, hidden_units_},
544	                             decoder_input_buf_ + hidden_units_offset)},
545	                     {"finished",
546	                      Tensor(MEMORY_GPU, TYPE_BOOL, {local_batch_size * beam_width}, finished_buf_ + id_offset)},
547	                     {"input_lengths",
548	                      Tensor(MEMORY_GPU, TYPE_INT32, {local_batch_size * beam_width}, sequence_lengths + id_offset)},
549	                     {"total_padding_tokens",
550	                      Tensor(MEMORY_GPU,
551	                             TYPE_INT32,
552	                             {local_batch_size * beam_width},
553	                             tiled_total_padding_count_ + id_offset)},
554	                     {"max_input_length", Tensor(MEMORY_CPU, TYPE_INT32, {1}, &max_input_length)},
555	                     {"step", Tensor(MEMORY_CPU, TYPE_INT32, {1}, &step)},
556	                     {"ite", Tensor(MEMORY_CPU, TYPE_INT32, {1}, &ite)},
557	                     {"masked_tokens",
558	                      Tensor(MEMORY_GPU,
559	                             TYPE_BOOL,
560	                             {local_batch_size * beam_width, memory_len},
561	                             masked_tokens_ + id_offset * memory_len)}});
562	                if (beam_width > 1) {
563	                    decoder_input_tensors.insert({"cache_indirection",
564	                                                  Tensor(MEMORY_GPU,
565	                                                         TYPE_INT32,
566	                                                         {local_batch_size, beam_width, memory_len},
567	                                                         cache_indirections_[src_indir_idx] + id_offset * memory_len)});
568	                }
569	
570	#ifdef FP8_MHA
571	                using cache_type = T1;
572	#else
573	                using cache_type = T2;
574	#endif
575	
576	                TensorMap decoder_output_tensors(
577	                    {{"decoder_output",
578	                      Tensor(MEMORY_GPU,
579	                             high_precision_data_type,
580	                             {local_batch_size * beam_width, hidden_units_},
581	                             decoder_output_buf_ + hidden_units_offset)},
582	                     {"key_cache", Tensor(MEMORY_GPU, getTensorType<cache_type>(), self_k_cache_shape, key_cache_)},
583	                     {"value_cache",
584	                      Tensor(MEMORY_GPU, getTensorType<cache_type>(), self_v_cache_shape, value_cache_)}});
585	
586	                gpt_decoder_->forward(
587	                    &decoder_output_tensors, &decoder_input_tensors, &gpt_weights->decoder_layer_weights);
588	            }
589	
590	            if (pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
591	                invokeGeneralLayerNorm(normed_decoder_output_buf_ + hidden_units_offset,
592	                                       decoder_output_buf_ + hidden_units_offset,
593	                                       gpt_weights->post_decoder_layernorm.gamma,
594	                                       gpt_weights->post_decoder_layernorm.beta,
595	                                       layernorm_eps_,
596	                                       local_batch_size * beam_width,
597	                                       hidden_units_,
598	                                       (float*)nullptr,
599	                                       0,
600	                                       stream_);
601	                sync_check_cuda_error();
602	
603	                // TODO Support FP8 GEMM
604	                if (tensor_para_.world_size_ == 1) {
605	                    float alpha = 1.0f;
606	                    float beta  = 0.0f;
607	                    cublas_wrapper_->Gemm(CUBLAS_OP_T,
608	                                          CUBLAS_OP_N,
609	                                          vocab_size_padded_,  // n
610	                                          local_batch_size * beam_width,
611	                                          hidden_units_,  // k
612	                                          &alpha,
613	                                          padded_embedding_kernel_ptr_,
614	                                          sizeof(T2) == 2 ? CUDA_R_16BF : CUDA_R_32F,
615	                                          hidden_units_,  // k
616	                                          normed_decoder_output_buf_ + hidden_units_offset,
617	                                          sizeof(T2) == 2 ? CUDA_R_16BF : CUDA_R_32F,
618	                                          hidden_units_,  // k
619	                                          &beta,
620	                                          logits_buf_ + vocab_size_units_offset,
621	                                          CUDA_R_32F,
622	                                          vocab_size_padded_, /* n */
623	                                          CUDA_R_32F,
624	                                          cublasGemmAlgo_t(-1));
625	                }
626	                else {
627	                    FT_CHECK(vocab_size_padded_ % tensor_para_.world_size_ == 0);
628	                    const int local_vocab_size = vocab_size_padded_ / tensor_para_.world_size_;
629	                    float     alpha            = 1.0f;
630	                    float     beta             = 0.0f;
631	                    cublas_wrapper_->Gemm(CUBLAS_OP_T,
632	                                          CUBLAS_OP_N,
633	                                          local_vocab_size,  // n
634	                                          local_batch_size * beam_width,
635	                                          hidden_units_,  // k
636	                                          &alpha,
637	                                          padded_embedding_kernel_ptr_
638	                                              + tensor_para_.rank_ * local_vocab_size * hidden_units_,
639	                                          sizeof(T2) == 2 ? CUDA_R_16BF : CUDA_R_32F,
640	                                          hidden_units_,  // k
641	                                          normed_decoder_output_buf_ + hidden_units_offset,
642	                                          sizeof(T2) == 2 ? CUDA_R_16BF : CUDA_R_32F,
643	                                          hidden_units_,  // k
644	                                          &beta,
645	                                          nccl_logits_buf_ + vocab_size_units_offset
646	                                              + tensor_para_.rank_ * local_batch_size * beam_width * local_vocab_size,
647	                                          CUDA_R_32F,
648	                                          local_vocab_size, /* n */
649	                                          CUDA_R_32F,
650	                                          cublasGemmAlgo_t(-1));
651	                    ftNcclAllGather(nccl_logits_buf_ + vocab_size_units_offset,
652	                                    nccl_logits_buf_ + vocab_size_units_offset,
653	                                    local_batch_size * beam_width * local_vocab_size,
654	                                    tensor_para_.rank_,
655	                                    tensor_para_,
656	                                    stream_);
657	                    check_cuda_error(cudaStreamSynchronize(stream_));
658	                    invokeTransposeAxis01(logits_buf_ + vocab_size_units_offset,
659	                                          nccl_logits_buf_ + vocab_size_units_offset,
660	                                          tensor_para_.world_size_,
661	                                          local_batch_size * beam_width,
662	                                          local_vocab_size,
663	                                          stream_);
664	                }
665	
666	                int                                     tmp_local_batch_size       = local_batch_size;
667	                bool                                    is_initialize_random_table = step == max_input_length;
668	                std::unordered_map<std::string, Tensor> dynamic_decode_input_tensors{
669	                    {"logits",
670	                     Tensor{MEMORY_GPU, TYPE_FP32, {batch_size, beam_width, vocab_size_padded_}, logits_buf_}},
671	                    {"embedding_bias", Tensor{MEMORY_GPU, data_type, {vocab_size_padded_}, nullptr}},
672	                    {"step", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &step}},
673	                    {"max_input_length", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &max_input_length}},
674	                    {"end_id", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size}, end_ids_buf_}},
675	                    {"input_lengths",
676	                     Tensor{MEMORY_GPU, TYPE_INT32, {batch_size, beam_width}, tiled_input_lengths_buf_}},
677	                    {"ite", Tensor{MEMORY_CPU, TYPE_UINT32, {1}, &ite}},
678	                    {"src_key_cache", Tensor{MEMORY_GPU, data_type, self_k_cache_shape, key_cache_}},
679	                    {"src_value_cache", Tensor{MEMORY_GPU, data_type, self_v_cache_shape, value_cache_}},
680	                    {"src_cache_indirection",
681	                     Tensor{MEMORY_GPU,
682	                            TYPE_INT32,
683	                            {local_batch_size, beam_width, max_output_seq_len},
684	                            cache_indirections_[src_indir_idx] + id_offset * max_output_seq_len}},
685	                    {"local_batch_size", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &tmp_local_batch_size}},
686	                    {"is_initialize_random_table", Tensor{MEMORY_CPU, TYPE_BOOL, {1}, &is_initialize_random_table}}};
687	
688	                for (auto t = input_tensors->begin(); t != input_tensors->end(); ++t) {
689	                    dynamic_decode_input_tensors.insert(*t);
690	                }
691	
692	                // common outputs
693	                std::unordered_map<std::string, Tensor> dynamic_decode_output_tensors{
694	                    {"output_ids",
695	                     Tensor{MEMORY_GPU, TYPE_INT32, {max_seq_len, batch_size, beam_width}, output_ids_buf_}},
696	                    {"finished", Tensor{MEMORY_GPU, TYPE_BOOL, {batch_size * beam_width}, finished_buf_}},
697	                    {"cum_log_probs", Tensor{MEMORY_GPU, TYPE_FP32, {batch_size * beam_width}, cum_log_probs_}},
698	                    {"parent_ids",
699	                     Tensor{MEMORY_GPU, TYPE_INT32, {max_seq_len, batch_size, beam_width}, parent_ids_buf_}},
700	                    {"sequence_length", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size * beam_width}, sequence_lengths}},
701	                    {"tgt_cache_indirection",
702	                     Tensor{MEMORY_GPU,
703	                            TYPE_INT32,
704	                            {local_batch_size, beam_width, max_output_seq_len},
705	                            cache_indirections_[tgt_indir_idx] + id_offset * max_output_seq_len}}};
706	
707	                for (auto t = output_tensors->begin(); t != output_tensors->end(); ++t) {
708	                    dynamic_decode_output_tensors.insert(*t);
709	                }
710	
711	                dynamic_decode_layer_->forward(&dynamic_decode_output_tensors, &dynamic_decode_input_tensors);
712	            }
713	
714	            if (pipeline_para_.world_size_ > 1) {
715	                NCCLCHECK(ncclGroupStart());
716	                ftNcclBroadCast(output_ids_buf_ + step * batch_size * beam_width,
717	                                batch_size * beam_width,
718	                                pipeline_para_.world_size_ - 1,
719	                                pipeline_para_,
720	                                stream_);
721	
722	                ftNcclBroadCast(
723	                    sequence_lengths, batch_size * beam_width, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
724	
725	                ftNcclBroadCast(
726	                    finished_buf_, batch_size * beam_width, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
727	
728	                if (beam_width > 1) {
729	                    // TODO(bhsueh) Check that do we need this broadcast
730	                    ftNcclBroadCast(parent_ids_buf_ + step * batch_size * beam_width,
731	                                    batch_size * beam_width,
732	                                    pipeline_para_.world_size_ - 1,
733	                                    pipeline_para_,
734	                                    stream_);
735	
736	                    ftNcclBroadCast(cache_indirections_[tgt_indir_idx],
737	                                    batch_size * beam_width * max_output_seq_len,
738	                                    pipeline_para_.world_size_ - 1,
739	                                    pipeline_para_,
740	                                    stream_);
741	                }
742	                NCCLCHECK(ncclGroupEnd());
743	                check_cuda_error(cudaStreamSynchronize(stream_));
744	                sync_check_cuda_error();
745	            }
746	
747	            cudaD2Hcpy(h_finished_buf_, finished_buf_, batch_size * beam_width);
748	            uint sum = 0;
749	            for (uint i = 0; i < batch_size * beam_width; i++) {
750	                sum += (int)h_finished_buf_[i];
751	            }
752	            if (sum == batch_size * beam_width) {
753	                break;
754	            }
755	        }
756	
757	        if (step == initial_step + max_input_length) {
758	            /* We have just finished processing input: update the padding count:
759	             * total_padding_count += (max_input_length - input_lengths) */
760	            invokeUpdatePaddingCount(tiled_total_padding_count_,
761	                                     input_tensors->at("input_lengths").getPtr<int>(),
762	                                     max_input_length,
763	                                     batch_size,
764	                                     beam_width,
765	                                     stream_);
766	        }
767	    }
768	
769	    if (input_tensors->at("input_ids").shape[1] == 0) {
770	        if (beam_width > 1) {
771	            // For beam search, do gather_tree
772	            invokeGatherTree(transposed_output_ids_buf_,
773	                             sequence_lengths,
774	                             max_output_seq_len,
775	                             batch_size,
776	                             beam_width,
777	                             output_ids_buf_ + batch_size * beam_width,
778	                             parent_ids_buf_ + batch_size * beam_width,
779	                             end_ids_buf_,
780	                             stream_);
781	
782	            // transpose and take output_parent_ids as inter buffer
783	            invokeTransposeAxis01((int*)output_tensors->at("output_ids").data,
784	                                  transposed_output_ids_buf_,
785	                                  max_output_seq_len - 1,
786	                                  batch_size * beam_width,
787	                                  1,
788	                                  stream_);
789	        }
790	        else {
791	            // For sampling, only transpose the results to output_tensor
792	            invokeTransposeAxis01((int*)output_tensors->at("output_ids").data,
793	                                  output_ids_buf_ + batch_size * beam_width,
794	                                  max_output_seq_len - 1,
795	                                  batch_size * beam_width,
796	                                  1,
797	                                  stream_);
798	        }
799	    }
800	    else {
801	        // For sampling, it is equivalent to all parent ids are 0.
802	        gatherTreeParam param;
803	        param.beams = transposed_output_ids_buf_;
804	        // Remove prompt length if possible
805	        param.max_sequence_lengths = sequence_lengths;
806	        // add sequence_length 1 here because the sequence_length of time step t is t - 1
807	        param.max_sequence_length_final_step = 1;
808	        // response input lengths (used to slice the ids during postprocessing)
809	        param.response_input_lengths     = output_tensors->count("response_input_lengths") ?
810	                                               output_tensors->at("response_input_lengths").getPtr<int>() :
811	                                               nullptr;
812	        param.max_time                   = max_output_seq_len;
813	        param.batch_size                 = batch_size;
814	        param.beam_width                 = beam_width;
815	        param.step_ids                   = output_ids_buf_;
816	        param.parent_ids                 = beam_width == 1 ? nullptr : parent_ids_buf_;
817	        param.end_tokens                 = end_ids_buf_;
818	        param.max_input_length           = max_input_length;
819	        param.prefix_soft_prompt_lengths = input_tensors->count("prefix_soft_prompt_lengths") ?
820	                                               input_tensors->at("prefix_soft_prompt_lengths").getPtr<int>() :
821	                                               nullptr;
822	        param.input_lengths              = tiled_input_lengths_buf_;
823	        // param.p_prompt_tuning_prompt_lengths  = has_p_prompt_tuning_ ? tiled_prompt_lengths_buf_ : nullptr;
824	        param.p_prompt_tuning_prompt_lengths      = nullptr;
825	        const int max_input_without_prompt_length = max_input_length;
826	        param.max_input_without_prompt_length     = max_input_without_prompt_length;
827	        param.max_prefix_soft_prompt_length       = max_prefix_soft_prompt_length;
828	        param.stream                              = stream_;
829	        param.output_ids                          = output_tensors->at("output_ids").getPtr<int>();
830	        // NOTE: need to remove all prompt virtual tokens
831	        invokeGatherTree(param);
832	        sync_check_cuda_error();
833	    }
834	}
835	
836	template<typename T1, typename T2>
837	size_t GptFP8<T1, T2>::getPipelineParallelRank()
838	{
839	    return pipeline_para_.rank_;
840	}
841	
842	template<typename T1, typename T2>
843	size_t GptFP8<T1, T2>::getPipelineParallelSize()
844	{
845	    return pipeline_para_.world_size_;
846	}
847	
848	template<typename T1, typename T2>
849	size_t GptFP8<T1, T2>::getTensorParallelRank()
850	{
851	    return tensor_para_.rank_;
852	}
853	
854	template<typename T1, typename T2>
855	size_t GptFP8<T1, T2>::getTensorParallelSize()
856	{
857	    return tensor_para_.world_size_;
858	}
859	
860	template<typename T1, typename T2>
861	bool* GptFP8<T1, T2>::getFinishBuffer()
862	{
863	    return finished_buf_;
864	}
865	
866	// template class GptFP8<__nv_fp8_e4m3>;
867	template class GptFP8<__nv_fp8_e4m3, __nv_bfloat16>;
868	// template class GptFP8<__nv_bfloat16, __nv_fp8_e4m3>;
869	// template class GptFP8<__nv_bfloat16, __nv_bfloat16>;
870	
871	}  // namespace fastertransformer
