31	__inline__ __device__ float tanh_opt(float x)
32	{
33	    return tanh(x);
34	#if (__CUDA_ARCH__ >= 750)
35	    float r;
36	    asm("tanh.approx.f32 %0,%1; \n\t" : "=f"(r) : "f"(x));
37	    return r;
38	#else
39	    const float exp_val = -1.f * fabs(2 * x);
40	    return copysignf_pos((1.0f - __expf(exp_val)) / (__expf(exp_val) + 1.0f), x);
41	#endif
42	}
