44	template<typename T>
45	__inline__ __device__ T gelu(T x)
46	{
47	    float f_x = (float)(x);
48	    float cdf = 0.5f * (1.0f + tanh_opt((0.7978845608028654f * (f_x + 0.044715f * f_x * f_x * f_x))));
49	    return (T)(f_x * cdf);
50	}
