52	template<>
53	__inline__ __device__ __nv_bfloat162 gelu(__nv_bfloat162 val)
54	{
55	    __nv_bfloat162 val_pow3 = __hmul2(val, __hmul2(val, val));
56	    float2         tmp_pow  = cuda_cast<float2>(val_pow3);
57	    float2         tmp      = cuda_cast<float2>(val);
58	
59	    tmp.x = 0.5f * (1.0f + tanh_opt((0.7978845608028654f * (tmp.x + 0.044715f * tmp_pow.x))));
60	    tmp.y = 0.5f * (1.0f + tanh_opt((0.7978845608028654f * (tmp.y + 0.044715f * tmp_pow.y))));
61	    return __hmul2(val, __float22bfloat162_rn(tmp));
62	}
