113	// NOTE: input is bfloat (pack8 to have 128 bit input, and 64 bit output)
114	template<>
115	__global__ void FP8AddBiasGelu(FP8ActivationParam<__nv_fp8_e4m3, __nv_bfloat16> param)
116	{
117	    float         input_scale     = __ldg(param.input_scale);
118	    float         output_scale    = __ldg(param.output_scale);
119	    constexpr int Packed_Elements = 8;
120	    using packed_out              = __nv_fp8_8_e4m3;
121	    using packed_bias             = __nv_bfloat168;
122	    using packed_in               = __nv_bfloat168;
123	    packed_out*  out_ptr          = (packed_out*)param.out;
124	    packed_in*   in_ptr           = (packed_in*)param.in;
125	    packed_bias* bias_ptr         = (packed_bias*)param.bias;
126	
127	    for (int id = blockIdx.x * blockDim.x + threadIdx.x; id < param.m * (param.n / Packed_Elements);
128	         id += blockDim.x * gridDim.x) {
129	        packed_in   val  = in_ptr[id];
130	        packed_bias bias = bias_ptr[id % (param.n / Packed_Elements)];
131	        packed_out  val_output;
132	#pragma unroll
133	        for (int i = 0; i < Packed_Elements; i++) {
134	            val_output.array[i] = __nv_fp8_e4m3(gelu((float)val.array[i] + (float)bias.array[i]) * output_scale);
135	        }
136	        // f_val.x = gelu(f_val.x + f_bias.x) * output_scale;
137	        // f_val.y = gelu(f_val.y + f_bias.x) * output_scale;
138	        // val = hmul2(gelu(hadd2(val, bias)), output_scale_2);
139	        // val = hmul2(gelu(hadd2(val, bias)), output_scale_2);
140	
141	        out_ptr[id] = val_output;
142	    }
143	}
