145	template<typename T1, typename T2>
146	void invokeFP8AddBiasGelu(FP8ActivationParam<T1, T2> param)
147	{
148	    FT_CHECK(param.n % 8 == 0);
149	    // NOTE: input data type is bfloat now
150	    const int data_type_factor = 8;  // pack 8 elements for bfloat16 input
151	    const int total_packs      = (param.n * param.m) / data_type_factor;
152	    dim3      block(256);
153	    int       num_packs_per_thread = 1;
154	    while ((total_packs + (block.x * num_packs_per_thread) - 1) / (block.x * num_packs_per_thread) > 512) {
155	        num_packs_per_thread *= 2;
156	    }
157	    dim3 grid((total_packs + (block.x * num_packs_per_thread) - 1) / (block.x * num_packs_per_thread));
158	    FP8AddBiasGelu<<<grid, block, 0, param.stream>>>(param);
159	}
