219	template<>
220	__global__ void FP8AddBiasRelu(FP8ActivationParam<__nv_fp8_e4m3, __nv_bfloat16> param)
221	{
222	    float            input_scale  = __ldg(param.input_scale);
223	    float            output_scale = __ldg(param.output_scale);
224	    __nv_fp8x2_e4m3* out_ptr      = (__nv_fp8x2_e4m3*)param.out;
225	    __nv_bfloat162*  in_ptr       = (__nv_bfloat162*)param.in;
226	    __nv_bfloat162*  bias_ptr     = (__nv_bfloat162*)param.bias;
227	
228	    __nv_bfloat162 input_scale_2  = __floats2bfloat162_rn(input_scale, input_scale);
229	    __nv_bfloat162 output_scale_2 = __floats2bfloat162_rn(output_scale, output_scale);
230	
231	    for (int id = blockIdx.x * blockDim.x + threadIdx.x; id < param.m * (param.n / 2); id += blockDim.x * gridDim.x) {
232	        __nv_bfloat162 val  = in_ptr[id];
233	        __nv_bfloat162 bias = bias_ptr[id % (param.n / 2)];
234	        val                 = hadd2(val, bias);
235	        val.x               = val.x > (__nv_bfloat16)0.0f ? val.x : (__nv_bfloat16)0.0f;
236	        val.y               = val.y > (__nv_bfloat16)0.0f ? val.y : (__nv_bfloat16)0.0f;
237	        val                 = hmul2(val, output_scale_2);
238	
239	        out_ptr[id] = __nv_fp8x2_e4m3(val);
240	    }
241	}
