244	void invokeFP8AddBiasRelu(FP8ActivationParam<T1, T2> param)
245	{
246	    FT_CHECK(param.n % 2 == 0);
247	    // NOTE: input data type is bfloat now
248	    const int data_type_factor = 2;  // 1 for fp32, 2 for fp16/bf16, 4 for fp86
249	    dim3      block, grid;
250	    if (param.n / 4 / data_type_factor <= 1024) {
251	        block.x = param.n / 4 / data_type_factor;
252	        grid.x  = param.m;
253	    }
254	    else {
255	        block.x = 1024;
256	        grid.x  = ceil(param.m * param.n / 1024.);
257	    }
258	    FP8AddBiasRelu<<<grid, block, 0, param.stream>>>(param);
259	}
