126	template<typename T1, typename T2>
127	void BertFP8<T1, T2>::allocateBuffer(size_t batch_size, size_t seq_len)
128	{
129	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
130	    h_pinned_token_num_ptr_ = (size_t*)allocator_->reMalloc(h_pinned_token_num_ptr_, sizeof(size_t), true, true);
131	    padding_offset_         = (int*)allocator_->reMalloc(padding_offset_, sizeof(int) * batch_size * seq_len, false);
132	    trt_mha_padding_offset_ =
133	        (int*)allocator_->reMalloc(trt_mha_padding_offset_, sizeof(int) * (2 * batch_size + 1), false);
134	
135	    attention_mask_ = (T1*)allocator_->reMalloc(attention_mask_, sizeof(T1) * batch_size * seq_len * seq_len, false);
136	
137	    bert_in_buffer_ = (T1*)allocator_->reMalloc(
138	        bert_in_buffer_, sizeof(T1) * batch_size * seq_len * head_num_ * size_per_head_, false);
139	    attn_out_buf_    = (T1*)allocator_->reMalloc(attn_out_buf_, sizeof(T1) * batch_size * seq_len * d_model_, false);
140	    bf16_out_tensor_ = (T2*)allocator_->reMalloc(bf16_out_tensor_, sizeof(T2) * batch_size * seq_len * d_model_, false);
141	    bert_out_buffer_ = (T1*)allocator_->reMalloc(
142	        bert_out_buffer_, sizeof(T1) * batch_size * seq_len * head_num_ * size_per_head_, false);
143	
144	    if (layernorm_type_ == LayerNormType::post_layernorm) {
145	        normed_from_tensor_  = nullptr;
146	        normed_attn_out_buf_ = nullptr;
147	    }
148	    else {
149	        normed_from_tensor_ =
150	            (T1*)allocator_->reMalloc(normed_from_tensor_, sizeof(T1) * batch_size * seq_len * d_model_, false);
151	        normed_attn_out_buf_ =
152	            (T1*)allocator_->reMalloc(normed_attn_out_buf_, sizeof(T1) * batch_size * seq_len * d_model_, false);
153	    }
154	
155	    first_token_tensor_ = (T2*)allocator_->reMalloc(first_token_tensor_, sizeof(T2) * batch_size * d_model_, false);
156	}
