158	template<typename T1, typename T2>
159	void BertFP8<T1, T2>::freeBuffer()
160	{
161	    allocator_->free((void**)(&h_pinned_token_num_ptr_), true);
162	    allocator_->free((void**)(&padding_offset_));
163	    allocator_->free((void**)(&trt_mha_padding_offset_));
164	
165	    allocator_->free((void**)(&attention_mask_));
166	    allocator_->free((void**)(&bert_in_buffer_));
167	    allocator_->free((void**)(&attn_out_buf_));
168	    allocator_->free((void**)(&bf16_out_tensor_));
169	    allocator_->free((void**)(&bert_out_buffer_));
170	
171	    if (layernorm_type_ == LayerNormType::post_layernorm) {
172	        normed_from_tensor_  = nullptr;
173	        normed_attn_out_buf_ = nullptr;
174	    }
175	    else {
176	        allocator_->free((void**)(&normed_from_tensor_));
177	        allocator_->free((void**)(&normed_attn_out_buf_));
178	    }
179	    allocator_->free((void**)(&first_token_tensor_));
180	}
