182	template<typename T1, typename T2>
183	void BertFP8<T1, T2>::forward(TensorMap*                   output_tensors,
184	                              TensorMap*                   input_tensors,
185	                              const BertFP8Weight<T1, T2>* bert_weights)
186	{
187	    // input_tensors:
188	    //      input_ids, int, [batch, seq_len]
189	    //      sequence_lengths, int, [batch]
190	    //      token_type_ids, int, [batch, seq_len]
191	    // output tensors:
192	    //      output_hidden_state [batch, seqlen, d_model_]
193	    //      ft_pooled_output, bfloat, [batch, d_model_], optional, the results of first token, only used for
194	    //      classification.
195	
196	    const size_t request_batch_size = input_tensors->at("input_ids").shape[0];
197	    const size_t request_seq_len    = input_tensors->at("input_ids").shape[1];
198	    FT_CHECK(input_tensors->size() >= 2);
199	    FT_CHECK(request_batch_size == input_tensors->at("sequence_lengths").shape[0]);
200	    FT_CHECK(input_tensors->at("sequence_lengths").shape.size() == 1);
201	    allocateBuffer(request_batch_size, request_seq_len);
202	    FT_CHECK(output_tensors->at("output_hidden_state").type == DataType::TYPE_FP16);
203	
204	    const int* sequence_lengths = reinterpret_cast<const int*>(input_tensors->at("sequence_lengths").data);
205	
206	    size_t  h_token_num;
207	    Tensor* padding_offset_tensor_ptr     = nullptr;
208	    Tensor* trt_padding_offset_tensor_ptr = nullptr;
209	
210	    AttentionType attention_type = attention_type_;
211	
212	    FT_CHECK(attention_type != AttentionType::UNFUSED_MHA);  // not support UNFUSED_MHA now
213	    if (isFusedMHA(attention_type) == false) {
214	        PUSH_RANGE("invokeBuildEncoderAttentionMask");
215	        invokeBuildEncoderAttentionMask(
216	            attention_mask_, sequence_lengths, request_batch_size, request_seq_len, stream_);
217	        sync_check_cuda_error();
218	        POP_RANGE;
219	    }
220	
221	    if (isPaddedMHA(attention_type)) {
222	        h_token_num = request_batch_size * request_seq_len;
223	        cudaMemsetAsync(padding_offset_, 0, sizeof(int) * h_token_num, stream_);
224	
225	        PUSH_RANGE("invokeGetTrtPaddingOffset");
226	        invokeGetTrtPaddingOffset(
227	            trt_mha_padding_offset_, sequence_lengths, request_batch_size, request_seq_len, stream_);
228	        POP_RANGE;
229	        sync_check_cuda_error();
230	
231	        padding_offset_tensor_ptr =
232	            new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{h_token_num}, padding_offset_);
233	        trt_padding_offset_tensor_ptr = new Tensor(
234	            MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size * 2 + 1}, trt_mha_padding_offset_);
235	    }
236	    else {
237	        PUSH_RANGE("invokeGetPaddingOffset");
238	        invokeGetPaddingOffset(h_pinned_token_num_ptr_,
239	                               &h_token_num,
240	                               padding_offset_,
241	                               sequence_lengths,
242	                               request_batch_size,
243	                               request_seq_len,
244	                               stream_);
245	        sync_check_cuda_error();
246	        POP_RANGE;
247	
248	        PUSH_RANGE("invokeGetTrtPaddingOffset");
249	        invokeGetTrtPaddingOffset(trt_mha_padding_offset_, sequence_lengths, request_batch_size, stream_);
250	        POP_RANGE;
251	        sync_check_cuda_error();
252	
253	        padding_offset_tensor_ptr =
254	            new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{h_token_num}, padding_offset_);
255	        trt_padding_offset_tensor_ptr =
256	            new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size + 1}, trt_mha_padding_offset_);
257	    }
258	
259	    {
260	        RemovePaddingEmbLookupLayerNormFP8OutParam<T1, T2> param{
261	            bert_out_buffer_,
262	            input_tensors->at("input_ids").getPtr<int>(),
263	            input_tensors->isExist("position_ids") ? input_tensors->at("position_ids").getPtr<int>() : nullptr,
264	            input_tensors->isExist("token_type_ids") ? input_tensors->at("token_type_ids").getPtr<int>() : nullptr,
265	            padding_offset_,
266	            bert_weights->word_embeddings,
267	            bert_weights->position_embeddings,
268	            bert_weights->token_type_embeddings,
269	            bert_weights->embeddings_layernorm.gamma,
270	            bert_weights->embeddings_layernorm.beta,
271	            bert_weights->bert_layer_weights[0].attention_weights.query_weight.input_scale_inv,
272	            sequence_lengths,
273	            (int)h_token_num,
274	            (int)d_model_,
275	            (int)request_batch_size,
276	            (int)request_seq_len,
277	            0,  // pad_token_id
278	            stream_,
279	            false,
280	        };
281	        PUSH_RANGE("invokeRemovePaddingEmbLookupLayerNormFP8Out");
282	        invokeRemovePaddingEmbLookupLayerNormFP8Out(param);
283	        sync_check_cuda_error();
284	        POP_RANGE;
285	    }
286	
287	    DataType data_type                = getTensorType<T1>();
288	    DataType high_precision_data_type = getTensorType<T2>();
289	    for (uint i = 0; i < num_layer_; i++) {
290	        const T1* from_tensor = bert_out_buffer_;
291	        T1*       out_tensor  = bert_out_buffer_;
292	
293	        const BertFP8LayerWeight<T1, T2>* layer_weight = &bert_weights->bert_layer_weights[i];
294	
295	        if (layernorm_type_ == LayerNormType::pre_layernorm) {
296	            if (fp8_mode_ == 1) {
297	                FT_CHECK(false);
298	            }
299	            else if (fp8_mode_ == 2) {
300	                // Need to layernorm kernel to support fp8 input.
301	                GeneralFP8IOPostLayerNormParam<T1, T2> param{
302	                    normed_from_tensor_,
303	                    from_tensor,
304	                    layer_weight->attn_layernorm_weights.gamma,
305	                    layer_weight->attn_layernorm_weights.beta,
306	                    nullptr,
307	                    layer_weight->attention_weights.query_weight.input_scale_inv,
308	                    (int)h_token_num,
309	                    (int)d_model_,
310	                    stream_,
311	                    true};
312	                sync_check_cuda_error();
313	            }
314	        }
315	
316	        // Attention
317	        {
318	            TensorMap attn_input_tensors = TensorMap(std::unordered_map<std::string, Tensor>{
319	                {"input_hidden_state",
320	                 Tensor{MEMORY_GPU,
321	                        data_type,
322	                        {h_token_num, d_model_},
323	                        layernorm_type_ == LayerNormType::pre_layernorm ? normed_from_tensor_ : from_tensor}},
324	                {"attention_mask",
325	                 Tensor{MEMORY_GPU,
326	                        data_type,
327	                        {request_batch_size, 1, request_seq_len, request_seq_len},
328	                        attention_mask_}},
329	                {"attention_type", Tensor{MEMORY_CPU, TYPE_VOID, {1}, &attention_type}}});
330	            if (padding_offset_tensor_ptr != nullptr) {
331	                attn_input_tensors.insert("padding_offset", *padding_offset_tensor_ptr);
332	            }
333	            if (trt_padding_offset_tensor_ptr != nullptr) {
334	                attn_input_tensors.insert("trt_padding_offset", *trt_padding_offset_tensor_ptr);
335	            }
336	
337	            TensorMap attn_output_tensors = TensorMap(std::unordered_map<std::string, Tensor>{
338	                {"output_hidden_state", Tensor{MEMORY_GPU, data_type, {h_token_num, d_model_}, attn_out_buf_}}});
339	
340	            attention_layer_->forward(&attn_output_tensors, &attn_input_tensors, &layer_weight->attention_weights);
341	        }
342	
343	        if (layernorm_type_ == LayerNormType::post_layernorm) {
344	            PUSH_RANGE("post layernorm 1");
345	            if (fp8_mode_ == 1) {
346	                FT_CHECK_WITH_INFO(false, "invokeGeneralFP8IOAddBiasResidualPostLayerNorm not support fp8_mode 1 now");
347	                // GeneralFP8IOAddBiasResidualPostLayerNormParam<T1, T2> param{
348	                //     attn_out_buf_,
349	                //     attn_out_buf_,
350	                //     from_tensor,
351	                //     layer_weight->attn_layernorm_weights.gamma,
352	                //     layer_weight->attn_layernorm_weights.beta,
353	                //     layer_weight->attention_weights.attention_output_weight.bias,
354	                //     layer_weight->attention_weights.attention_output_weight.output_scale,
355	                //     layer_weight->attention_weights.attention_output_weight.scale,
356	                //     layer_weight->attention_weights.attention_output_weight.per_channel_scale_min,
357	                //     layer_weight->ffn_weights.intermediate_weight.input_scale_inv,
358	                //     layer_weight->attention_weights.query_weight.input_scale,
359	                //     (int)h_token_num,
360	                //     (int)d_model_,
361	                //     stream_};
362	                // invokeGeneralFP8IOAddBiasResidualPostLayerNorm<T1, T2, PER_CHANNEL_WEIGHT_PER_TENSOR_ACT>(param);
363	            }
364	            else if (fp8_mode_ == 2) {
365	                GeneralFP8IOAddBiasResidualPostLayerNormParam<T1, T2> param{
366	                    attn_out_buf_,
367	                    attn_out_buf_,
368	                    from_tensor,
369	                    layer_weight->attn_layernorm_weights.gamma,
370	                    layer_weight->attn_layernorm_weights.beta,
371	#ifdef FUSE_GEMM_ACT
372	                    nullptr,
373	#else
374	                    layer_weight->attention_weights.attention_output_weight.bias,
375	#endif
376	                    layer_weight->attention_weights.attention_output_weight.output_scale,
377	                    nullptr,
378	                    nullptr,
379	                    layer_weight->ffn_weights.intermediate_weight.input_scale_inv,
380	                    layer_weight->attention_weights.query_weight.input_scale,
381	                    (int)h_token_num,
382	                    (int)d_model_,
383	                    stream_};
384	                invokeGeneralFP8IOAddBiasResidualPostLayerNorm(param);
385	            }
386	            POP_RANGE;
387	        }
388	        else if (layernorm_type_ == LayerNormType::pre_layernorm) {
389	            // GeneralFP8AddBiasResidualPreLayerNormParam<T1, T2> param{
390	            //     normed_attn_out_buf_,
391	            //     attn_out_buf_,
392	            //     from_tensor,
393	            //     layer_weight->attention_weights.attention_output_weight.bias,
394	            //     layer_weight->ffn_layernorm_weights.gamma,
395	            //     layer_weight->ffn_layernorm_weights.beta,
396	            //     (const float*)layer_weight->attention_weights.attention_output_weight.scale,
397	            //     (const float*)layer_weight->ffn_weights.intermediate_weight.input_scale,
398	            //     h_token_num,
399	            //     d_model_,
400	            //     stream_,
401	            //     true};
402	            // invokeGeneralFP8AddBiasResidualPreLayerNorm(param);
403	            // sync_check_cuda_error();
404	        }
405	
406	        // FFN
407	        {
408	            TensorMap ffn_input_tensors  = TensorMap(std::unordered_map<std::string, Tensor>{
409	                 {"input_hidden_state",
410	                  Tensor{MEMORY_GPU,
411	                        data_type,
412	                        std::vector<size_t>{h_token_num, d_model_},
413	                        layernorm_type_ == LayerNormType::pre_layernorm ? normed_attn_out_buf_ : attn_out_buf_}}});
414	            TensorMap ffn_output_tensors = TensorMap(std::unordered_map<std::string, Tensor>{
415	                {"output_hidden_state",
416	                 Tensor{MEMORY_GPU, data_type, std::vector<size_t>{h_token_num, d_model_}, out_tensor}}});
417	            ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &layer_weight->ffn_weights);
418	        }
419	
420	        if (layernorm_type_ == LayerNormType::post_layernorm) {
421	            PUSH_RANGE("post layernorm 2");
422	            if (fp8_mode_ == 1) {
423	                FT_CHECK_WITH_INFO(false, "invokeGeneralFP8IOAddBiasResidualPostLayerNorm not support fp8_mode 1 now");
424	                // GeneralFP8IOAddBiasResidualPostLayerNormParam<T1, T2> param{
425	                //     out_tensor,
426	                //     out_tensor,
427	                //     attn_out_buf_,
428	                //     layer_weight->ffn_layernorm_weights.gamma,
429	                //     layer_weight->ffn_layernorm_weights.beta,
430	                //     layer_weight->ffn_weights.output_weight.bias,
431	                //     layer_weight->ffn_weights.output_weight.output_scale,
432	                //     layer_weight->ffn_weights.output_weight.scale,
433	                //     layer_weight->ffn_weights.output_weight.per_channel_scale_min,
434	                //     i == num_layer_ - 1 ?
435	                //         layer_weight->attention_weights.query_weight.input_scale_inv :
436	                //         bert_weights->bert_layer_weights[i + 1]
437	                //             .attention_weights.query_weight.input_scale_inv,  // for next layer
438	                //     layer_weight->ffn_weights.intermediate_weight.input_scale,
439	                //     (int)h_token_num,
440	                //     (int)d_model_,
441	                //     stream_};
442	                // invokeGeneralFP8IOAddBiasResidualPostLayerNorm<T1, T2, PER_CHANNEL_WEIGHT_PER_TENSOR_ACT>(param);
443	            }
444	            else if (fp8_mode_ == 2) {
445	                GeneralFP8IOAddBiasResidualPostLayerNormParam<T1, T2> param{
446	                    out_tensor,
447	                    out_tensor,
448	                    attn_out_buf_,
449	                    layer_weight->ffn_layernorm_weights.gamma,
450	                    layer_weight->ffn_layernorm_weights.beta,
451	#ifdef FUSE_GEMM_ACT
452	                    layer_weight->ffn_weights.output_weight.bias,  // nullptr,
453	#else
454	                    layer_weight->ffn_weights.output_weight.bias,
455	#endif
456	                    layer_weight->ffn_weights.output_weight.output_scale,
457	                    nullptr,
458	                    nullptr,
459	                    i == num_layer_ - 1 ? layer_weight->attention_weights.query_weight.input_scale_inv :
460	                                          bert_weights->bert_layer_weights[i + 1]
461	                                              .attention_weights.query_weight.input_scale_inv,  // for next layer
462	                    layer_weight->ffn_weights.intermediate_weight.input_scale,
463	                    (int)h_token_num,
464	                    (int)d_model_,
465	                    stream_};
466	                invokeGeneralFP8IOAddBiasResidualPostLayerNorm(param);
467	            }
468	            POP_RANGE;
469	        }
470	        else if (layernorm_type_ == LayerNormType::pre_layernorm) {
471	            // invokeAddBiasResidual(out_tensor,
472	            //                       attn_out_buf_,
473	            //                       layer_weight->ffn_weights.output_weight.bias,
474	            //                       h_token_num,
475	            //                       d_model_,
476	            //                       stream_);
477	        }
478	        sync_check_cuda_error();
479	    }
480	
481	    if (layernorm_type_ == LayerNormType::pre_layernorm) {
482	        // invokeGeneralLayerNorm(bert_out_buffer_,
483	        //                        bert_out_buffer_,
484	        //                        bert_weights->post_transformer_layernorm_weights.gamma,
485	        //                        bert_weights->post_transformer_layernorm_weights.beta,
486	        //                        h_token_num,
487	        //                        d_model_,
488	        //                        stream_);
489	    }
490	
491	    {
492	        // because TRT does not support bfloat output now.
493	        QuantizeMatrixRebuildPaddingParam<half, T1, QUANTIZE_MODE::PER_TENSOR> param{
494	            output_tensors->at("output_hidden_state").getPtr<half>(),
495	            bert_out_buffer_,
496	            isPaddedMHA(attention_type) ? nullptr : padding_offset_,
497	            (int)h_token_num,
498	            (int)d_model_,
499	            bert_weights->bert_layer_weights[num_layer_ - 1].attention_weights.query_weight.input_scale,
500	            stream_};
501	        PUSH_RANGE("invokeQuantizeMatrixRebuildPadding");
502	        invokeQuantizeMatrixRebuildPadding<half, T1, QUANTIZE_MODE::PER_TENSOR>(param);
503	        sync_check_cuda_error();
504	        POP_RANGE;
505	    }
506	
507	    if (output_tensors->isExist("ft_pooled_output")) {
508	        {
509	            getLastTokenDequantizeParam<T2, T1> param{
510	                first_token_tensor_,
511	                bert_out_buffer_,
512	                bert_weights->bert_layer_weights[num_layer_ - 1].attention_weights.query_weight.input_scale,
513	                (int)request_batch_size,
514	                (int)request_seq_len,
515	                (int)d_model_,
516	                stream_};
517	            invokeGetLastTokenDequantize<T2, T1>(param);
518	            sync_check_cuda_error();
519	        }
520	
521	        {
522	            float alpha = 1.0f;
523	            float beta  = 0.0f;
524	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
525	                                  CUBLAS_OP_N,
526	                                  d_model_,
527	                                  request_batch_size,
528	                                  d_model_,
529	                                  &alpha,
530	                                  bert_weights->pooler_dense.kernel,
531	                                  CUDA_R_16BF,
532	                                  d_model_,
533	                                  first_token_tensor_,
534	                                  CUDA_R_16BF,
535	                                  d_model_,
536	                                  &beta,
537	                                  output_tensors->at("ft_pooled_output").getPtr<T2>(),
538	                                  CUDA_R_16BF,
539	                                  d_model_,
540	                                  CUDA_R_32F,
541	                                  cublasGemmAlgo_t(-1));
542	        }
543	
544	        {
545	            invokeAddBiasTanh(output_tensors->at("ft_pooled_output").getPtr<T2>(),
546	                              bert_weights->pooler_dense.bias,
547	                              request_batch_size,
548	                              d_model_,
549	                              stream_);
550	            sync_check_cuda_error();
551	        }
552	    }
553	
554	    if (is_free_buffer_after_forward_ == true) {
555	        freeBuffer();
556	    }
557	    sync_check_cuda_error();
558	
559	    if (padding_offset_tensor_ptr != nullptr) {
560	        delete padding_offset_tensor_ptr;
561	    }
562	    if (trt_padding_offset_tensor_ptr != nullptr) {
563	        delete trt_padding_offset_tensor_ptr;
564	    }
565	}
